export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "09:28。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校史館還沒有開門。正門拉著鐵捲門，側門虛掩著，留了一條縫——攝影組和工作人員從這裡進出。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在側門外面。沒有進去。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她說不要跟著她進校史館。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但我可以站在門外。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這裡看得見舊照片區。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "側門的縫剛好對著展廳深處。透過那條縫，他能看見靠後牆的那排舊照片展板——布條覆蓋了一半，幾個移動式展繩架靠在入口處。那裡是第四輪他看見未裁切照片的區域。那裡也是許星棠母親可能出現在舊檔案裡的地方。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）09:30。林主任會來。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）前幾輪他來過。每一輪都來。理由不一樣——有時候是「檢查展品」，有時候是「調整動線」。但行為一樣：拉繩、清場、不讓人靠近那排舊照片。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我不知道他在藏什麼。但我知道他每一輪都會做這件事。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "09:29。腳步聲從展廳另一頭傳來。不是一個人——是三個人。一個快、一個慢、一個急。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最先出現在視野裡的是兩個穿志工背心的學生。他們手裡各拿一捆紅色展繩，一邊走一邊小聲說話。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "跟在後面的是林主任。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "深灰色西裝。胸前別著校徽。金屬細框眼鏡。頭髮梳得很整齊。步伐比平常快半拍，像永遠在趕路。他的手背在身後，但手指在動——右手食指不停地點著左手手背，像在數什麼。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在緊張。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）每一輪他都緊張。表面理由是行政官腔，但他的手在抖。第四輪我離得近，看見他拉展繩的時候繩扣掉了兩次。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任走到舊照片區前，停住。他掃了一眼布條覆蓋的展板，轉向兩個學生志工。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "這邊等會兒要重新調整動線。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "先把繩拉起來。不要讓人靠近。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Student, character: "學生", dialogue: "林主任，這些照片不是開放參觀的嗎？流程表上寫——", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "流程表我會更新。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "先拉繩。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個學生對看了一眼。其中一個聳了聳肩，蹲下來開始把展繩架拉開。紅色的繩子在他們手裡晃，發出塑料撞擊的輕響。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任站在旁邊。他的目光掃過布條邊緣，落在最裡面一個展板上——那個位置掛著一組南翼整修時期的舊工作照。他的嘴唇動了一下，像在對自己說什麼，但沒有聲音。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那個位置。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第四輪我在那裡看見了未裁切照片。我爸在。她母親在。南翼整修後防災演練。還有那個很像邵叔的年輕警員。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在藏的就是這些。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "展繩拉好了。紅色的繩子從展板左側繞到右側，把整排舊照片圍了起來。林主任親手在最右邊的繩架上繫了一個結——他的手指緊捏到指節發白，繩結打得比平常緊了兩圈。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "今天這一區不開放。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "有人問就說在重新整理。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Student, character: "學生", dialogue: "好的。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩個學生收起多餘的繩子走了。林主任在原地又站了幾秒。他從西裝內袋裡摸出手機，看了一眼螢幕，臉色變了一下——不明顯，但透過側門的縫，顧言看見他的下顎收緊了。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他把手機塞回口袋，快步往展廳另一頭走了。步伐比來時更快。手指不再點了。拳頭攥著。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他接到消息了。或者他自己看了什麼東西被嚇到了。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不重要。重要的是——他來了。他拉了繩。他封了舊照片區。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和每一輪一樣。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一聲快門。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很輕。從展廳另一側傳來。顧言的視線穿過側門的縫，往聲音的方向看——許星棠站在展廳對面的角落，相機舉在眼前。她不知道什麼時候到的，不知道從哪個門進來的。她站在一排器材架的後面，半個身子藏在陰影裡。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她拍下了林主任。拍下了展繩。拍下了那排被蓋住的舊照片。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她放下相機，隔著整個展廳，看了顧言一眼。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看不見她的表情。距離太遠。但他知道她在看他。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她看見了。她親眼看見了。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一件。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在側門外。沒有進去。沒有靠近。沒有喊她的名字。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他只動了嘴唇。聲音壓得很低，低到自己都聽不太清。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "第一件。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "展廳另一側，許星棠的快門聲停了一下。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只是一下。然後她重新舉起相機，轉身從另一個側門走了。腳步聲很快就消失在雨裡。", background: Background.Chapter_6_Ch6_Act3_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她聽見了。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她的快門停了一下。那就是回答。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯還有兩件。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）10:15。行政組。南翼備用門禁卡。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這一次，她會跟我一起看。", background: Background.Chapter_6_Ch6_Act3_S0, portrait: Portrait.GuYan_Determined },
];
